3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: unknown; steps: Step[] };
14	
15	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
16	
17	const sumItemPremiums = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
19	
20	const quote = (step: Step): { premium: number } => ({
21	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
22	});
23	
24	export const runScenario = (input: unknown): unknown => {
25	  const scenario = input as Scenario;
26	  return { results: scenario.steps.map(quote) };
27	};
